        return UniversalLinkHandler.shared.handleUniversalLink(url)
    }
}

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedPaths = ["/promo"]
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard validateURL(url) else {
            print("Invalid universal link: \(url)")
            return false
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return false
        }
        
        if components.path == "/promo" {
            return handlePromoLink(components: components)
        }
        
        return false
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard let scheme = url.scheme, scheme == "https" else {
            return false
        }
        
        guard let host = url.host, allowedHosts.contains(host) else {
            return false
        }
        
        guard allowedPaths.contains(url.path) else {
            return false
        }
        
        return true
    }
    
    private func handlePromoLink(components: URLComponents) -> Bool {
        guard let queryItems = components.queryItems else {
            return false
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value
            case "discount":
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            default:
                break
            }
        }
        
        guard let validPromoCode = promoCode,
              let validDiscount = discount,
              validatePromoParameters(code: validPromoCode, discount: validDiscount) else {
            print("Invalid promo parameters")
            return false
        }
        
        applyPromotion(code: validPromoCode, discount: validDiscount)
        return true
    }
    
    private func validatePromoParameters(code: String, discount: Int) -> Bool {
        let codePattern = "^[A-Z0-9]{3,20}$"
        let codePredicate = NSPredicate(format: "SELF MATCHES %@", codePattern)
        
        guard codePredicate.evaluate(with: code) else {
            return false
        }
        
        guard discount > 0 && discount <= 100 else {
            return false
        }
        
        return true
    }
    
    private func applyPromotion(code: String, discount: Int) {
        PromoManager.shared.applyPromoCode(code: code, discount: discount)
        
        DispatchQueue.main.async {
            NotificationCenter.default.post(
                name: NSNotification.Name("PromoCodeApplied"),
                object: nil,
                userInfo: ["code": code, "discount": discount]
            )
        }
    }
}

class PromoManager {
    static let shared = PromoManager()
    
    private var currentPromoCode: String?
    private var currentDiscount: Int?
    
    private init() {}
    
    func applyPromoCode(code: String, discount: Int) {
        currentPromoCode = code
        currentDiscount = discount
        
        UserDefaults.standard.set(code, forKey: "activePromoCode")
        UserDefaults.standard.set(discount, forKey: "activeDiscount")
        UserDefaults.standard.set(Date(), forKey: "promoAppliedDate")
        
        print("Promo code applied: \(code) with \(discount)% discount")
    }
    
    func getCurrentPromo() -> (code: String, discount: Int)? {
        guard let code = UserDefaults.standard.string(forKey: "activePromoCode"),
              let discount = UserDefaults.standard.object(forKey: "activeDiscount") as? Int else {
            return nil
        }
        return (code, discount)
    }
    
    func clearPromo() {
        currentPromoCode = nil
        currentDiscount = nil
        UserDefaults.standard.removeObject(forKey: "activePromoCode")
        UserDefaults.standard.removeObject(forKey: "activeDiscount")
        UserDefaults.standard.removeObject(forKey: "promoAppliedDate")
    }
    
    func calculateDiscountedPrice(originalPrice: Double) -> Double {
        guard let discount = currentDiscount else {
            return originalPrice
        }
        let discountAmount = originalPrice * Double(discount) / 100.0
        return originalPrice - discountAmount
    }
}

